noncompliant:
// Mixing type definition with variable declaration
struct Container {
    int size;
    char* data;
} container, *containerPtr; // Noncompliant

// Enum definition with variable
enum Status {
    ACTIVE,
    INACTIVE,
    PENDING
} currentStatus; // Noncompliant

// Union with variable declaration
union Data {
    int intValue;
    float floatValue;
} dataUnion; // Noncompliant

compliant:
// Separate type definition from variable declaration
struct Container {
    int size;
    char* data;
};
struct Container container;
struct Container* containerPtr;

// Separate enum and variable
enum Status {
    ACTIVE,
    INACTIVE,
    PENDING
};
enum Status currentStatus;

// Separate union and variable
union Data {
    int intValue;
    float floatValue;
};
union Data dataUnion;
